import{_ as o,P as n,I as s,g as r,j as a,l as i}from"./chunks/framework.CbuNJfvM.js";const g=JSON.parse('{"title":"syntax in ghūl","description":"","frontmatter":{},"headers":[],"relativePath":"syntax.md","filePath":"syntax.md"}'),c={name:"syntax.md"};function l(d,e,h,p,f,m){const t=n("GhulExample");return s(),r("div",null,[e[0]||(e[0]=a('<h1 id="syntax-in-ghul" tabindex="-1">syntax in ghūl <a class="header-anchor" href="#syntax-in-ghul" aria-label="Permalink to &quot;syntax in ghūl&quot;">​</a></h1><h2 id="projects-and-files" tabindex="-1">projects and files <a class="header-anchor" href="#projects-and-files" aria-label="Permalink to &quot;projects and files&quot;">​</a></h2><p>A ghūl project is composed of a set of ghūl source files. Source files should have a <code>.ghul</code> file extension, and must be UTF-8 text.</p><p>Each source file can contain zero, one or more global definitions. Definitions can be in any order and in any file. Source files can have any name, provided they have a <code>.ghul</code> extension, and can be in any folder under the project root (subject to any source file glob pattern given in the <code>.ghulproj</code>)</p><h2 id="tokens-and-trees" tabindex="-1">tokens and trees <a class="header-anchor" href="#tokens-and-trees" aria-label="Permalink to &quot;tokens and trees&quot;">​</a></h2><p>Source files are translated into various kinds of tokens. Some tokens are a fixed sequence of characters (like the keyword <code>while</code>). Others are composed of characters according to various rules (identifiers, strings, numbers etc.)</p><p>With a couple of exceptions, ghūl tokens are similar to most common programming languages. The exceptions are:</p><h3 id="operators" tabindex="-1">operators <a class="header-anchor" href="#operators" aria-label="Permalink to &quot;operators&quot;">​</a></h3><p>Operators are any contiguous string of operator characters. This is only significant in the rare case where running together the characters that comprise two different operators might not have the result you expect</p><h3 id="escaped-identifiers" tabindex="-1">escaped identifiers <a class="header-anchor" href="#escaped-identifiers" aria-label="Permalink to &quot;escaped identifiers&quot;">​</a></h3><p>When it appears at the beginning of an identifier, the backtick character <code>`</code> acts as an escape. So where <code>while</code> is a ghūl keyword, <code> `while</code> is an identifier which starts with a backtick</p><h2 id="block-structure" tabindex="-1">block structure <a class="header-anchor" href="#block-structure" aria-label="Permalink to &quot;block structure&quot;">​</a></h2><p>ghūl is a <a href="https://en.wikipedia.org/wiki/Block_(programming)" target="_blank" rel="noreferrer">block structured programming language</a>. Source code in ghūl is composed of blocks, typically many of them, with blocks nested inside other blocks.</p><p>Blocks are delimited by keywords. The keywords that begin and end a block are specific to each different kind of block. This way of delimited blocks is descended from the ALGOL family of languages, most specifically from <a href="https://en.wikipedia.org/wiki/ALGOL_68" target="_blank" rel="noreferrer">ALGOL 68</a>. It has the advantage of making the block structure clearer, both to someone reading the code and to the compiler.</p>',14)),i(t,{name:"syntax-1"}),e[1]||(e[1]=a('<p>In this example <code>then</code>, <code>else</code> and <code>fi</code> all delimit blocks. The blocks they delimit contain statement lists.</p><h2 id="semicolons" tabindex="-1">semicolons <a class="header-anchor" href="#semicolons" aria-label="Permalink to &quot;semicolons&quot;">​</a></h2><p>Semicolons are required: to separate statements and definitions.</p><p>While the compiler <em>could</em> still unambiguously parse correct programs without requiring semicolons anywhere, having them at the end expression statements makes it clearer to the parser if the expression is incomplete or not well formed.</p><h2 id="definitions-and-statements" tabindex="-1">definitions and statements <a class="header-anchor" href="#definitions-and-statements" aria-label="Permalink to &quot;definitions and statements&quot;">​</a></h2><p>Blocks in ghūl can contain definitions, statements, or a mix of both. Which is permitted in a given block depends on the type of block.</p><h2 id="file-structure" tabindex="-1">file structure <a class="header-anchor" href="#file-structure" aria-label="Permalink to &quot;file structure&quot;">​</a></h2><p>At its top level a ghūl source file contains <a href="/definitions.html">definitions</a> and <code>use</code> directives. There is no required ordering and no file header — a source file is simply a collection of definitions.</p>',8)),i(t,{name:"syntax-2"}),e[2]||(e[2]=a('<p>The definitions in a file can be global functions, properties, classes, structs, traits, unions and enums, or <code>namespace</code> blocks that group definitions under a name. A definition is visible to the rest of the project regardless of which file it appears in, so how source is split across files is purely a matter of organisation.</p><p>A file that declares any <code>namespace</code> must place all of its definitions inside namespaces. A file with no namespace at all has its definitions placed in a private namespace of their own, which is convenient for small programs and tests. Namespaces, <code>use</code> and symbol visibility are covered in full under <a href="/definitions.html#namespaces">definitions</a>.</p><p>Execution of a program begins at a function named <code>entry</code>.</p>',3))])}const b=o(c,[["render",l]]);export{g as __pageData,b as default};
